def calcular_total(consumo, tarifa):
    return consumo * tarifa

print(f"Total: R$ {calcular_total(180, 0.92):.2f}")

def avaliar_beneficio(renda_per_capita, dependentes, teto=750.0):
    elegivel = renda_per_capita <= teto
    if elegivel:
        valor = 120.0 + (dependentes * 30.0)
    else:
        valor = 0.0
    return elegivel, valor

status, valor = avaliar_beneficio(680.0, 2)
print(f"Elegível? {status}")
print(f"Valor: R$ {valor:.2f}")
